package au.edu.utas.kit305.tutorial05

import android.annotation.SuppressLint
import android.app.AlertDialog
import android.content.Intent
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.util.Log
import android.view.ViewGroup
import android.widget.EditText
import android.widget.LinearLayout
import androidx.core.widget.doAfterTextChanged
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import au.edu.utas.kit305.tutorial05.databinding.ActivityMainBinding
import au.edu.utas.kit305.tutorial05.databinding.HouseListItemBinding

import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.firestore.toObject
import com.google.firebase.ktx.Firebase

const val FIREBASE_TAG = "FirebaseLogging"
const val HOUSE_INDEX = "House_Index"
const val MOVIE_INDEX = "Movie_Index"
const val HOUSE_NAME_EXTRA = "house_name"
val items = mutableListOf<Movie>()
val houses = mutableListOf<House>()

class MainActivity : AppCompatActivity() {
    private lateinit var ui: ActivityMainBinding
    private var housesExpanded = false
    private val filteredHouses = mutableListOf<House>()
    private var houseSearchQuery: String = ""

    @SuppressLint("SetTextI18n")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        ui = ActivityMainBinding.inflate(layoutInflater)
        setContentView(ui.root)

        ui.lblMovieCount.text = getString(R.string.house_count_format, houses.size)
        val houseAdapter = HouseAdapter(houseList = filteredHouses)
        houseAdapter.setToggleCallback {
            housesExpanded = !housesExpanded
            houseAdapter.setExpanded(housesExpanded)
        }
        ui.myList.adapter = houseAdapter

        ui.myList.layoutManager = LinearLayoutManager(this)
        ui.btnAddHouse.setOnClickListener { addHouse() }
        ui.txtSearchHouses.doAfterTextChanged {
            houseSearchQuery = it?.toString()?.trim().orEmpty()
            applyHouseFilter()
        }

        val db = Firebase.firestore
        Log.d("FIREBASE", "Firebase connected: ${db.app.name}")

        val housesCollection = db.collection("houses")
        ui.lblMovieCount.text = "Loading..."
        housesCollection
            .get()
            .addOnSuccessListener { result ->
                houses.clear()
                for (document in result) {
                    val house = document.toObject<House>()
                    house.id = document.id
                    houses.add(house)
                }
                applyHouseFilter()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error reading houses", it)
                ui.lblMovieCount.text = getString(R.string.house_count_format, 0)
            }
    }

    override fun onResume() {
        super.onResume()
        applyHouseFilter()
    }

    private fun addHouse() {
        val newHouse = House(customerName = "New Customer", address = "New Address")

        Firebase.firestore.collection("houses")
            .add(newHouse)
            .addOnSuccessListener {
                newHouse.id = it.id
                houses.add(0, newHouse)
                applyHouseFilter()
                ui.myList.scrollToPosition(0)
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error creating house", it)
            }
    }

    private fun promptDeleteHouse(house: House) {

        AlertDialog.Builder(this)
            .setMessage(R.string.delete_house_confirm)
            .setPositiveButton(R.string.delete) { _, _ -> deleteHouse(house) }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    private fun showEditHouseDialog(house: House) {

        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            val p = (16 * resources.displayMetrics.density).toInt()
            setPadding(p, p, p, 0)
        }

        val nameEdit = EditText(this).apply {
            hint = "Customer name"
            setText(house.customerName ?: "")
        }

        val addressEdit = EditText(this).apply {
            hint = "Address"
            setText(house.address ?: "")
        }

        layout.addView(nameEdit)
        layout.addView(addressEdit)

        AlertDialog.Builder(this)
            .setTitle("Edit House")
            .setView(layout)
            .setPositiveButton("Save") { _, _ ->
                val newName = nameEdit.text.toString().trim()
                val newAddress = addressEdit.text.toString().trim()
                if (newName.isBlank() || newAddress.isBlank()) return@setPositiveButton
                updateHouse(house, newName, newAddress)
            }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    private fun updateHouse(house: House, customerName: String, address: String) {
        val houseId = house.id ?: return

        val updates = mapOf(
            "customerName" to customerName,
            "address" to address
        )

        Firebase.firestore.collection("houses").document(houseId)
            .update(updates)
            .addOnSuccessListener {
                house.customerName = customerName
                house.address = address
                applyHouseFilter()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error updating house", it)
            }
    }

    private fun deleteHouse(house: House) {
        val houseId = house.id ?: return

        val db = Firebase.firestore
        db.collection("rooms")
            .whereEqualTo("houseId", houseId)
            .get()
            .addOnSuccessListener { result ->
                val batch = db.batch()
                for (document in result.documents) {
                    batch.delete(document.reference)
                }
                batch.delete(db.collection("houses").document(houseId))

                batch.commit()
                    .addOnSuccessListener {
                        houses.removeAll { it.id == houseId }
                        applyHouseFilter()
                    }
                    .addOnFailureListener {
                        Log.e(FIREBASE_TAG, "Error deleting house and rooms", it)
                    }
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error finding rooms for house delete", it)
            }
    }

    private fun openQuoteFromHouse(house: House) {
        val houseId = house.id ?: return

        val i = Intent(this, QuoteActivity::class.java)
        i.putExtra(HOUSE_ID_EXTRA, houseId)
        i.putExtra(HOUSE_NAME_EXTRA, house.customerName ?: getString(R.string.quote_title_default))
        startActivity(i)
    }

    private fun openRoomsFromHouse(house: House) {
        val i = Intent(this, HouseDetails::class.java)
        i.putExtra(HOUSE_INDEX, -1)
        i.putExtra(HOUSE_ID_EXTRA, house.id)
        i.putExtra(HOUSE_NAME_EXTRA, house.customerName ?: "House")
        startActivity(i)
    }

    private fun applyHouseFilter() {
        val q = houseSearchQuery.lowercase()
        filteredHouses.clear()
        if (q.isBlank()) {
            filteredHouses.addAll(houses)
        } else {
            filteredHouses.addAll(
                houses.filter { house ->
                    val name = house.customerName.orEmpty().lowercase()
                    val address = house.address.orEmpty().lowercase()
                    name.contains(q) || address.contains(q)
                }
            )
        }
        ui.myList.adapter?.notifyDataSetChanged()
        ui.lblMovieCount.text = getString(R.string.house_count_format, filteredHouses.size)
    }

    private fun showHouseTapOptions(position: Int) {
        if (position < 0 || position >= houses.size) return

        AlertDialog.Builder(this)
            .setTitle(R.string.house_actions_title)
            .setItems(arrayOf(getString(R.string.edit_house_action), getString(R.string.open_rooms_action))) { _, which ->
                when (which) {
                    0 -> showEditHouseDialog(houses[position])
                    1 -> {
                        val i = Intent(this, HouseDetails::class.java)
                        i.putExtra(HOUSE_INDEX, position)
                        i.putExtra(HOUSE_ID_EXTRA, houses[position].id)
                        i.putExtra(HOUSE_NAME_EXTRA, houses[position].customerName ?: "House")
                        startActivity(i)
                    }
                }
            }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    inner class HouseHolder(var ui: HouseListItemBinding) : RecyclerView.ViewHolder(ui.root)
    inner class MoreHolder(itemView: android.widget.Button) : RecyclerView.ViewHolder(itemView)

    inner class HouseAdapter(private val houseList: MutableList<House>) : RecyclerView.Adapter<RecyclerView.ViewHolder>() {

        private val itemTypeHouse = 0
        private val itemTypeToggle = 1
        private val itemsPerPage = 2

        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): RecyclerView.ViewHolder {
            return if (viewType == itemTypeHouse) {
                val ui = HouseListItemBinding.inflate(layoutInflater, parent, false)
                HouseHolder(ui)
            } else {
                val button = android.widget.Button(parent.context)
                button.setOnClickListener { onToggleExpand?.invoke() }
                button.layoutParams = ViewGroup.LayoutParams(
                    ViewGroup.LayoutParams.MATCH_PARENT,
                    ViewGroup.LayoutParams.WRAP_CONTENT
                )
                MoreHolder(button)
            }
        }

        override fun getItemCount(): Int {
            val visibleCount = if (isExpanded) houseList.size else minOf(itemsPerPage, houseList.size)
            val hasToggle = houseList.size > itemsPerPage
            return visibleCount + (if (hasToggle) 1 else 0)
        }

        override fun getItemViewType(position: Int): Int {
            val visibleCount = if (isExpanded) houseList.size else minOf(itemsPerPage, houseList.size)
            return if (position < visibleCount) itemTypeHouse else itemTypeToggle
        }

        override fun onBindViewHolder(holder: RecyclerView.ViewHolder, position: Int) {
            if (holder is HouseHolder && position < houseList.size) {
                val house = houseList[position]
                holder.ui.txtName.text = house.customerName ?: "Unnamed customer"
                holder.ui.txtAddress.text = house.address ?: "No address"

                holder.ui.root.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openRoomsFromHouse(house)
                }

                holder.ui.btnEditHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    showEditHouseDialog(house)
                }

                holder.ui.btnCreateRoomHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openRoomsFromHouse(house)
                }

                holder.ui.btnDeleteHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    promptDeleteHouse(house)
                }

                holder.ui.btnViewQuoteHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openQuoteFromHouse(house)
                }
            } else if (holder is MoreHolder) {
                val button = holder.itemView as android.widget.Button
                button.text = if (isExpanded) "Show Less Houses" else "Show More Houses"
            }
        }

        fun setExpanded(expanded: Boolean) {
            isExpanded = expanded
            notifyDataSetChanged()
        }

        fun setToggleCallback(callback: (() -> Unit)?) {
            onToggleExpand = callback
        }

        private var isExpanded: Boolean = false
        private var onToggleExpand: (() -> Unit)? = null
    }
}

package au.edu.utas.kit305.tutorial05

import android.annotation.SuppressLint
import android.app.AlertDialog
import android.content.Intent
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.util.Log
import android.view.ViewGroup
import android.widget.EditText
import android.widget.LinearLayout
import androidx.core.widget.doAfterTextChanged
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import au.edu.utas.kit305.tutorial05.databinding.ActivityMainBinding
import au.edu.utas.kit305.tutorial05.databinding.HouseListItemBinding

import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.firestore.toObject
import com.google.firebase.ktx.Firebase

const val FIREBASE_TAG = "FirebaseLogging"
const val HOUSE_INDEX = "House_Index"
const val MOVIE_INDEX = "Movie_Index"
const val HOUSE_NAME_EXTRA = "house_name"
val items = mutableListOf<Movie>()
val houses = mutableListOf<House>()

class MainActivity : AppCompatActivity() {
    private lateinit var ui: ActivityMainBinding
    private var housesExpanded = false
    private val filteredHouses = mutableListOf<House>()
    private var houseSearchQuery: String = ""

    @SuppressLint("SetTextI18n")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        ui = ActivityMainBinding.inflate(layoutInflater)
        setContentView(ui.root)

        ui.lblMovieCount.text = getString(R.string.house_count_format, houses.size)
        val houseAdapter = HouseAdapter(houseList = filteredHouses)
        houseAdapter.setToggleCallback {
            housesExpanded = !housesExpanded
            houseAdapter.setExpanded(housesExpanded)
        }
        ui.myList.adapter = houseAdapter

        ui.myList.layoutManager = LinearLayoutManager(this)
        ui.btnAddHouse.setOnClickListener { showAddHouseDialog() }
        ui.txtSearchHouses.doAfterTextChanged {
            houseSearchQuery = it?.toString()?.trim().orEmpty()
            applyHouseFilter()
        }

        val db = Firebase.firestore
        Log.d("FIREBASE", "Firebase connected: ${db.app.name}")

        val housesCollection = db.collection("houses")
        ui.lblMovieCount.text = "Loading..."
        housesCollection
            .get()
            .addOnSuccessListener { result ->
                houses.clear()
                for (document in result) {
                    val house = document.toObject<House>()
                    house.id = document.id
                    houses.add(house)
                }
                applyHouseFilter()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error reading houses", it)
                ui.lblMovieCount.text = getString(R.string.house_count_format, 0)
            }
    }

    override fun onResume() {
        super.onResume()
        applyHouseFilter()
    }

    private fun showAddHouseDialog() {
        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            val p = (16 * resources.displayMetrics.density).toInt()
            setPadding(p, p, p, 0)
        }

        val nameEdit = EditText(this).apply {
            hint = getString(R.string.house_dialog_customer_name_hint)
        }

        val addressEdit = EditText(this).apply {
            hint = getString(R.string.house_dialog_address_hint)
        }

        layout.addView(nameEdit)
        layout.addView(addressEdit)

        val dialog = AlertDialog.Builder(this)
            .setTitle(R.string.house_dialog_add_title)
            .setView(layout)
            .setPositiveButton(R.string.save, null)
            .setNegativeButton(R.string.cancel, null)
            .create()

        dialog.setOnShowListener {
            dialog.getButton(AlertDialog.BUTTON_POSITIVE).setOnClickListener {
                val newName = nameEdit.text.toString().trim()
                val newAddress = addressEdit.text.toString().trim()

                val valid = validateHouseInput(nameEdit, addressEdit, newName, newAddress)
                if (!valid) return@setOnClickListener

                addHouse(newName, newAddress)
                dialog.dismiss()
            }
        }

        dialog.show()
    }

    private fun addHouse(customerName: String, address: String) {
        val newHouse = House(customerName = customerName, address = address)

        Firebase.firestore.collection("houses")
            .add(newHouse)
            .addOnSuccessListener {
                newHouse.id = it.id
                houses.add(0, newHouse)
                applyHouseFilter()
                ui.myList.scrollToPosition(0)
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error creating house", it)
            }
    }

    private fun promptDeleteHouse(house: House) {

        AlertDialog.Builder(this)
            .setMessage(R.string.delete_house_confirm)
            .setPositiveButton(R.string.delete) { _, _ -> deleteHouse(house) }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    private fun showEditHouseDialog(house: House) {

        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            val p = (16 * resources.displayMetrics.density).toInt()
            setPadding(p, p, p, 0)
        }

        val nameEdit = EditText(this).apply {
            hint = getString(R.string.house_dialog_customer_name_hint)
            setText(house.customerName ?: "")
        }

        val addressEdit = EditText(this).apply {
            hint = getString(R.string.house_dialog_address_hint)
            setText(house.address ?: "")
        }

        layout.addView(nameEdit)
        layout.addView(addressEdit)

        val dialog = AlertDialog.Builder(this)
            .setTitle(R.string.house_dialog_edit_title)
            .setView(layout)
            .setPositiveButton(R.string.save, null)
            .setNegativeButton(R.string.cancel, null)
            .create()

        dialog.setOnShowListener {
            dialog.getButton(AlertDialog.BUTTON_POSITIVE).setOnClickListener {
                val newName = nameEdit.text.toString().trim()
                val newAddress = addressEdit.text.toString().trim()

                val valid = validateHouseInput(nameEdit, addressEdit, newName, newAddress)
                if (!valid) return@setOnClickListener

                updateHouse(house, newName, newAddress)
                dialog.dismiss()
            }
        }

        dialog.show()
    }

    private fun containsLetter(value: String): Boolean = value.any { it.isLetter() }

    private fun validateHouseInput(
        nameEdit: EditText,
        addressEdit: EditText,
        newName: String,
        newAddress: String
    ): Boolean {
        var valid = true

        if (newName.isBlank()) {
            nameEdit.error = getString(R.string.error_customer_name_required)
            valid = false
        } else {
            nameEdit.error = null
        }

        when {
            newAddress.isBlank() -> {
                addressEdit.error = getString(R.string.error_address_required)
                valid = false
            }
            !containsLetter(newAddress) -> {
                // Prevent numeric-only addresses like "12345".
                addressEdit.error = getString(R.string.error_address_requires_letter)
                valid = false
            }
            else -> addressEdit.error = null
        }

        return valid
    }

    private fun updateHouse(house: House, customerName: String, address: String) {
        val houseId = house.id ?: return

        val updates = mapOf(
            "customerName" to customerName,
            "address" to address
        )

        Firebase.firestore.collection("houses").document(houseId)
            .update(updates)
            .addOnSuccessListener {
                house.customerName = customerName
                house.address = address
                applyHouseFilter()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error updating house", it)
            }
    }

    private fun deleteHouse(house: House) {
        val houseId = house.id ?: return

        val db = Firebase.firestore
        db.collection("rooms")
            .whereEqualTo("houseId", houseId)
            .get()
            .addOnSuccessListener { result ->
                val batch = db.batch()
                for (document in result.documents) {
                    batch.delete(document.reference)
                }
                batch.delete(db.collection("houses").document(houseId))

                batch.commit()
                    .addOnSuccessListener {
                        houses.removeAll { it.id == houseId }
                        applyHouseFilter()
                    }
                    .addOnFailureListener {
                        Log.e(FIREBASE_TAG, "Error deleting house and rooms", it)
                    }
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error finding rooms for house delete", it)
            }
    }

    private fun openQuoteFromHouse(house: House) {
        val houseId = house.id ?: return

        val i = Intent(this, QuoteActivity::class.java)
        i.putExtra(HOUSE_ID_EXTRA, houseId)
        i.putExtra(HOUSE_NAME_EXTRA, house.customerName ?: getString(R.string.quote_title_default))
        startActivity(i)
    }

    private fun openRoomsFromHouse(house: House) {
        val i = Intent(this, HouseDetails::class.java)
        i.putExtra(HOUSE_INDEX, -1)
        i.putExtra(HOUSE_ID_EXTRA, house.id)
        i.putExtra(HOUSE_NAME_EXTRA, house.customerName ?: "House")
        startActivity(i)
    }

    private fun applyHouseFilter() {
        val q = houseSearchQuery.lowercase()
        filteredHouses.clear()
        if (q.isBlank()) {
            filteredHouses.addAll(houses)
        } else {
            filteredHouses.addAll(
                houses.filter { house ->
                    val name = house.customerName.orEmpty().lowercase()
                    val address = house.address.orEmpty().lowercase()
                    name.contains(q) || address.contains(q)
                }
            )
        }
        ui.myList.adapter?.notifyDataSetChanged()
        ui.lblMovieCount.text = getString(R.string.house_count_format, filteredHouses.size)
    }

    private fun showHouseTapOptions(position: Int) {
        if (position < 0 || position >= houses.size) return

        AlertDialog.Builder(this)
            .setTitle(R.string.house_actions_title)
            .setItems(arrayOf(getString(R.string.edit_house_action), getString(R.string.open_rooms_action))) { _, which ->
                when (which) {
                    0 -> showEditHouseDialog(houses[position])
                    1 -> {
                        val i = Intent(this, HouseDetails::class.java)
                        i.putExtra(HOUSE_INDEX, position)
                        i.putExtra(HOUSE_ID_EXTRA, houses[position].id)
                        i.putExtra(HOUSE_NAME_EXTRA, houses[position].customerName ?: "House")
                        startActivity(i)
                    }
                }
            }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    inner class HouseHolder(var ui: HouseListItemBinding) : RecyclerView.ViewHolder(ui.root)
    inner class MoreHolder(itemView: android.widget.Button) : RecyclerView.ViewHolder(itemView)

    inner class HouseAdapter(private val houseList: MutableList<House>) : RecyclerView.Adapter<RecyclerView.ViewHolder>() {

        private val itemTypeHouse = 0
        private val itemTypeToggle = 1
        private val itemsPerPage = 2

        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): RecyclerView.ViewHolder {
            return if (viewType == itemTypeHouse) {
                val ui = HouseListItemBinding.inflate(layoutInflater, parent, false)
                HouseHolder(ui)
            } else {
                val button = android.widget.Button(parent.context)
                button.setOnClickListener { onToggleExpand?.invoke() }
                button.layoutParams = ViewGroup.LayoutParams(
                    ViewGroup.LayoutParams.MATCH_PARENT,
                    ViewGroup.LayoutParams.WRAP_CONTENT
                )
                MoreHolder(button)
            }
        }

        override fun getItemCount(): Int {
            val visibleCount = if (isExpanded) houseList.size else minOf(itemsPerPage, houseList.size)
            val hasToggle = houseList.size > itemsPerPage
            return visibleCount + (if (hasToggle) 1 else 0)
        }

        override fun getItemViewType(position: Int): Int {
            val visibleCount = if (isExpanded) houseList.size else minOf(itemsPerPage, houseList.size)
            return if (position < visibleCount) itemTypeHouse else itemTypeToggle
        }

        override fun onBindViewHolder(holder: RecyclerView.ViewHolder, position: Int) {
            if (holder is HouseHolder && position < houseList.size) {
                val house = houseList[position]
                holder.ui.txtName.text = house.customerName ?: "Unnamed customer"
                holder.ui.txtAddress.text = house.address ?: "No address"

                holder.ui.root.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openRoomsFromHouse(house)
                }

                holder.ui.btnEditHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    showEditHouseDialog(house)
                }

                holder.ui.btnCreateRoomHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openRoomsFromHouse(house)
                }

                holder.ui.btnDeleteHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    promptDeleteHouse(house)
                }

                holder.ui.btnViewQuoteHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openQuoteFromHouse(house)
                }
            } else if (holder is MoreHolder) {
                val button = holder.itemView as android.widget.Button
                button.text = if (isExpanded) "Show Less Houses" else "Show More Houses"
            }
        }

        fun setExpanded(expanded: Boolean) {
            isExpanded = expanded
            notifyDataSetChanged()
        }

        fun setToggleCallback(callback: (() -> Unit)?) {
            onToggleExpand = callback
        }

        private var isExpanded: Boolean = false
        private var onToggleExpand: (() -> Unit)? = null
    }
}

package au.edu.utas.kit305.tutorial05

import android.content.Intent
import android.graphics.Color
import android.os.Bundle
import android.util.Log
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.ImageView
import android.widget.ProgressBar
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import org.json.JSONArray
import org.json.JSONObject
import java.net.HttpURLConnection
import java.net.URL
import kotlin.math.roundToInt

const val EXTRA_PRODUCT_TYPE = "product_type"
const val EXTRA_SPACE_WIDTH = "space_width"
const val EXTRA_SPACE_HEIGHT = "space_height"
const val RESULT_PRODUCT_ID = "result_product_id"
const val RESULT_PRODUCT_NAME = "result_product_name"
const val RESULT_PANEL_COUNT = "result_panel_count"

data class CompatibilityResult(
    val compatible: Boolean,
    val panelCount: Int = 1,
    val message: String = ""
)

fun checkCompatibility(product: Product, windowWidth: Int, windowHeight: Int): CompatibilityResult {
    // Floor products have no size constraints
    if (product.category != "window") return CompatibilityResult(true, 1, "")
    // No dimensions recorded yet — allow selection
    if (windowWidth <= 0 && windowHeight <= 0) return CompatibilityResult(true, 1, "No dimensions set")

    // Height check
    if (windowHeight > 0) {
        if (windowHeight < product.minHeight) {
            return CompatibilityResult(false, 0, "Too short: ${windowHeight}mm (min ${product.minHeight}mm required)")
        }
        if (windowHeight > product.maxHeight) {
            return CompatibilityResult(false, 0, "Too tall: ${windowHeight}mm (max ${product.maxHeight}mm allowed)")
        }
    }

    // Width check — iterate panel counts until one fits
    if (windowWidth > 0) {
        for (panels in 1..maxOf(1, product.maxPanelCount)) {
            val panelWidth = windowWidth.toDouble() / panels
            if (panelWidth >= product.minWidth && panelWidth <= product.maxWidth) {
                val msg = if (panels == 1) "Single panel — ${windowWidth}mm wide"
                          else "$panels panels — each ~${panelWidth.roundToInt()}mm wide"
                return CompatibilityResult(true, panels, msg)
            }
        }
        return when {
            windowWidth < product.minWidth ->
                CompatibilityResult(false, 0, "Too narrow: ${windowWidth}mm (min ${product.minWidth}mm per panel)")
            product.maxPanelCount <= 1 ->
                CompatibilityResult(false, 0, "Too wide: ${windowWidth}mm exceeds ${product.maxWidth}mm (single panel only)")
            else ->
                CompatibilityResult(false, 0, "Cannot fit: ${windowWidth}mm cannot be split into " +
                    "1–${product.maxPanelCount} panels each ${product.minWidth}–${product.maxWidth}mm wide")
        }
    }

    return CompatibilityResult(true, 1, "")
}

class ProductListActivity : AppCompatActivity() {

    private lateinit var lstProducts: RecyclerView
    private lateinit var progressProducts: ProgressBar
    private lateinit var lblProductError: TextView
    private lateinit var lblTitle: TextView
    private lateinit var lblSpaceInfo: TextView

    private val products = mutableListOf<Product>()
    private var productType = "window"
    private var spaceWidthMm = 0
    private var spaceHeightMm = 0

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_product_list)

        lstProducts = findViewById(R.id.lstProducts)
        progressProducts = findViewById(R.id.progressProducts)
        lblProductError = findViewById(R.id.lblProductError)
        lblTitle = findViewById(R.id.lblProductListTitle)
        lblSpaceInfo = findViewById(R.id.lblSpaceInfo)

        productType = intent.getStringExtra(EXTRA_PRODUCT_TYPE) ?: "window"
        spaceWidthMm = intent.getIntExtra(EXTRA_SPACE_WIDTH, 0)
        spaceHeightMm = intent.getIntExtra(EXTRA_SPACE_HEIGHT, 0)

        val typeLabel = if (productType == "window") "Window" else "Floor"
        lblTitle.text = "Select a $typeLabel Product"

        val dimLabel = if (productType == "window") {
            "Window: ${spaceWidthMm}mm wide x ${spaceHeightMm}mm tall"
        } else {
            "Floor space: ${spaceWidthMm}mm x ${spaceHeightMm}mm"
        }
        lblSpaceInfo.text = dimLabel

        lstProducts.layoutManager = LinearLayoutManager(this)
        lstProducts.adapter = ProductAdapter(
            products = products,
            spaceWidthMm = spaceWidthMm,
            spaceHeightMm = spaceHeightMm,
            productType = productType
        ) { product, compat ->
            returnSelectedProduct(product, compat)
        }

        loadProductsFromApi()
    }

    private fun loadProductsFromApi() {
        progressProducts.visibility = View.VISIBLE
        lblProductError.visibility = View.GONE

        Thread {
            try {
                val endpoint = "https://utasbot.dev/kit305_2026/product?category=$productType"
                val url = URL(endpoint)
                val conn = (url.openConnection() as HttpURLConnection).apply {
                    requestMethod = "GET"
                    connectTimeout = 10000
                    readTimeout = 10000
                }

                val responseCode = conn.responseCode
                if (responseCode !in 200..299) {
                    runOnUiThread {
                        progressProducts.visibility = View.GONE
                        lblProductError.text = "Failed to load products ($responseCode)"
                        lblProductError.visibility = View.VISIBLE
                    }
                    conn.disconnect()
                    return@Thread
                }

                val responseText = conn.inputStream.bufferedReader().use { it.readText() }
                conn.disconnect()

                val parsedProducts = parseProducts(responseText)

                runOnUiThread {
                    progressProducts.visibility = View.GONE
                    products.clear()
                    products.addAll(parsedProducts)
                    lstProducts.adapter?.notifyDataSetChanged()
                    if (products.isEmpty()) {
                        lblProductError.text = "No $productType products returned by API."
                        lblProductError.visibility = View.VISIBLE
                    }
                }
            } catch (e: Exception) {
                runOnUiThread {
                    progressProducts.visibility = View.GONE
                    lblProductError.text = "Network error: ${e.message}"
                    lblProductError.visibility = View.VISIBLE
                }
                Log.e(FIREBASE_TAG, "Error loading products from API", e)
            }
        }.start()
    }

    private fun parseProducts(responseText: String): List<Product> {
        val out = mutableListOf<Product>()

        // Support both possible formats:
        // 1) { "data": [ ... ] }
        // 2) [ ... ]
        val array: JSONArray = if (responseText.trim().startsWith("{")) {
            val root = JSONObject(responseText)
            root.optJSONArray("data") ?: JSONArray()
        } else {
            JSONArray(responseText)
        }

        for (i in 0 until array.length()) {
            val obj = array.optJSONObject(i) ?: continue
            out.add(
                Product(
                    id = obj.optString("id"),
                    name = obj.optString("name"),
                    description = obj.optString("description"),
                    category = obj.optString("category"),
                    imageUrl = obj.optString("imageUrl").ifBlank { null },
                    pricePerSqm = obj.optDouble("price_per_sqm", 0.0),
                    minWidth = obj.optInt("min_width", 0),
                    maxWidth = obj.optInt("max_width", 9999),
                    minHeight = obj.optInt("min_height", 0),
                    maxHeight = obj.optInt("max_height", 9999),
                    maxPanelCount = obj.optInt("max_panels", 1),
                    variants = parseVariants(obj.optJSONArray("variants"))
                )
            )
        }

        return out
    }

    private fun parseVariants(variantsArray: JSONArray?): List<String> {
        if (variantsArray == null) return emptyList()
        val variants = mutableListOf<String>()
        for (i in 0 until variantsArray.length()) {
            variants.add(variantsArray.optString(i))
        }
        return variants
    }

    private fun returnSelectedProduct(product: Product, compat: CompatibilityResult) {
        val resultIntent = Intent()
        resultIntent.putExtra(RESULT_PRODUCT_ID, product.id)
        resultIntent.putExtra(RESULT_PRODUCT_NAME, product.name)
        resultIntent.putExtra(RESULT_PANEL_COUNT, compat.panelCount)
        setResult(RESULT_OK, resultIntent)
        finish()
    }

    class ProductViewHolder(itemView: View) : RecyclerView.ViewHolder(itemView) {
        val imgProduct: ImageView = itemView.findViewById(R.id.imgProduct)
        val txtName: TextView = itemView.findViewById(R.id.txtProductName)
        val txtDescription: TextView = itemView.findViewById(R.id.txtProductDescription)
        val txtPrice: TextView = itemView.findViewById(R.id.txtProductPrice)
        val txtConstraints: TextView = itemView.findViewById(R.id.txtProductConstraints)
        val txtCompatibility: TextView = itemView.findViewById(R.id.txtCompatibility)
    }

    class ProductAdapter(
        private val products: List<Product>,
        private val spaceWidthMm: Int,
        private val spaceHeightMm: Int,
        private val productType: String,
        private val onSelect: (Product, CompatibilityResult) -> Unit
    ) : RecyclerView.Adapter<ProductViewHolder>() {

        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ProductViewHolder {
            val v = LayoutInflater.from(parent.context)
                .inflate(R.layout.product_list_item, parent, false)
            return ProductViewHolder(v)
        }

        override fun getItemCount() = products.size

        override fun onBindViewHolder(holder: ProductViewHolder, position: Int) {
            val product = products[position]

            holder.txtName.text = product.name
            holder.txtDescription.text = product.description
            holder.txtPrice.text = "$${String.format("%.2f", product.pricePerSqm)} / m2"

            holder.txtConstraints.text = if (product.category == "window") {
                "W: ${product.minWidth}-${product.maxWidth}mm  H: ${product.minHeight}-${product.maxHeight}mm  Max panels: ${product.maxPanelCount}"
            } else {
                "Floor covering"
            }

            // Keep a built-in placeholder icon (no third-party image loader).
            holder.imgProduct.setImageResource(android.R.drawable.ic_menu_gallery)

            // Check if this product fits the window dimensions
            val compat = checkCompatibility(product, spaceWidthMm, spaceHeightMm)
            if (compat.compatible) {
                holder.txtCompatibility.text =
                    if (compat.message.isNotBlank()) "✓ ${compat.message}" else "✓ Compatible"
                holder.txtCompatibility.setTextColor(Color.parseColor("#2E7D32"))
                holder.itemView.alpha = 1.0f
                holder.itemView.setOnClickListener { onSelect(product, compat) }
            } else {
                // Incompatible — show why in red and block selection
                holder.txtCompatibility.text = "✗ ${compat.message}"
                holder.txtCompatibility.setTextColor(Color.parseColor("#C62828"))
                holder.itemView.alpha = 0.45f
                holder.itemView.setOnClickListener {
                    Toast.makeText(
                        holder.itemView.context,
                        "Cannot select: ${compat.message}",
                        Toast.LENGTH_LONG
                    ).show()
                }
            }
        }
    }
}

